$(document).ready(function(){Array.from(document.getElementsByClassName("container-md")).forEach(e=>{e.classList.add("container-xl"),e.classList.remove("container-md")}),Array.from(document.getElementsByClassName("col-xl-8")).forEach(e=>{e.classList.remove("col-xl-8")}),Array.from(document.getElementsByClassName("offset-xl-2")).forEach(e=>{e.classList.remove("offset-xl-2")})});